sql:
SELECT DISTINCT companies.company_id, industries.industry_name
FROM companies
JOIN industries ON companies.industry_id = industries.industry_id;

SELECT industry_name, average_revenue
FROM industries
WHERE average_revenue > 10000000;

SELECT c.name AS Company, i.industry_name AS Industry
FROM companies c
JOIN industries i ON c.industry_id = i.industry_id
WHERE i.average_growth_rate >= (
  SELECT AVG(average_growth_rate) FROM industries
);
